/// Parse AsciiTab from a string. Returns Ok or Error.
let parse (input: string) : Result<StringNameNode, string> =
    match run (stringNameParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
